<template>
  <div class="layout" :class="{'home-page': isHomePage}">
    <MainHeader :class="{'home-page': isHomePage}" />
    <router-view  />
    <MainFooter />
  </div>

</template>

<script>
import MainHeader from '@/components/MainHeader.vue'
import MainFooter from '@/components/MainFooter.vue'
import { useRoute } from 'vue-router';

export default {
  name: 'App',
  components: {
    MainHeader,
    MainFooter
  },
  computed: {
    isHomePage() {
      const route = useRoute();
      return route.path === '/'; 
    }
  }
}
</script>
